function filterTingkat(){const t=document.getElementById("filter-tingkat").value;document.querySelectorAll("#tatib-table tbody tr").forEach(e=>{const n=e.getAttribute("data-tingkat");e.style.display=""===t||n===t?"":"none"});document.querySelectorAll(".sanksi-tingkat").forEach(e=>{const n=e.getAttribute("data-tingkat");e.style.display=""===t||n===t?"":"none"})}function redirectToPage(t){window.location.href=t}